pattern.code:
@Configuration
class OpenApiConfiguration {
    @Bean
    fun openAPI(): OpenAPI {
        return OpenAPI()
            .info(Info()
                .title("EAF v1.0 API")
                .version("1.0.0")
                .description("Enterprise Application Framework REST API"))
            .components(Components()
                .addSecuritySchemes("bearer-jwt",
                    SecurityScheme()
                        .type(SecurityScheme.Type.HTTP)
                        .scheme("bearer")
                        .bearerFormat("JWT")))
    }
}
